import com.google.gson.GsonBuilder;

class GsonBuilderTest {

  @Test
  void testSetPrettyPrinting() {
    GsonBuilder builder = new GsonBuilder();
    // Initially prettyPrinting should be false (default)
    boolean initialPrettyPrinting = getPrettyPrinting(builder);
    assertFalse(initialPrettyPrinting);

    // Call setPrettyPrinting and verify it returns the same instance
    GsonBuilder returnedBuilder = builder.setPrettyPrinting();
    assertSame(builder, returnedBuilder);

    // After calling setPrettyPrinting, prettyPrinting should be true
    boolean updatedPrettyPrinting = getPrettyPrinting(builder);
    assertTrue(updatedPrettyPrinting);
  }

  private boolean getPrettyPrinting(GsonBuilder builder) {
    try {
      java.lang.reflect.Field field = GsonBuilder.class.getDeclaredField("prettyPrinting");
      field.setAccessible(true);
      return field.getBoolean(builder);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Failed to access prettyPrinting field via reflection: " + e.getMessage());
      return false;
    }
  }
}
